-- ============================================================================
-- SalzGuide — Events „gratis"-Feld + Anker-Korrekturen/Erweiterung (nach 0013).
-- Reihenfolge: ERST 0013 (Kategorie 'sport') ausführen, DANN diese Migration.
-- Idempotent. Im Supabase SQL-Editor ausführen.
--
-- Was passiert:
--  1. events.is_free (boolean) -> speist den „Gratis"-Filter/-Badge in der App.
--  2. Sport-Anker sind jetzt Kategorie 'sport' (statt 'kultur').
--  3. free-Status korrigiert (z.B. winter-opening-flachau/krampuslauf-hallein/
--     aperschnalzen -> teils; rauriser-literaturtage/schmiede-hallein -> ja).
--  4. 'open-mind-festival-argekultur' entfernt; 16 neue Anker ergänzt.
--  Der Admin-Aktiv-Schalter (active) bleibt erhalten (wird NICHT überschrieben).
-- ============================================================================

alter table public.events add column if not exists is_free boolean not null default false;
comment on column public.events.is_free is 'true = gratis Eintritt -> „Gratis"-Filter/Badge in der App.';

delete from public.event_anchors where key = 'open-mind-festival-argekultur';

on conflict (key) do update set
  name       = excluded.name,
  category   = excluded.category,
  region     = excluded.region,
  months     = excluded.months,
  timing     = excluded.timing,
  url        = excluded.url,
  free       = excluded.free,
  why        = excluded.why,
  note       = excluded.note,
  sort_order = excluded.sort_order;
  -- Hinweis: 'active' wird bewusst NICHT aktualisiert -> Admin-Ein/Aus bleibt erhalten.

